CREATE TABLE IF NOT EXISTS vehicles (id UUID DEFAULT gen_random_uuid() PRIMARY KEY,make TEXT NOT NULL,model TEXT NOT NULL,year INT,price DECIMAL(10,2) NOT NULL,available BOOLEAN DEFAULT true);CREATE TABLE IF NOT EXISTS vehicle_bookings (id UUID DEFAULT gen_random_uuid() PRIMARY KEY,vehicle_id UUID,custom er_name TEXT NOT NULL,custom er_email TEXT NOT NULL,start_date DATE NOT NULL,end_date DATE NOT NULL,total DECIMAL(10,2) NOT NULL,status TEXT DEFAULT 'pending');ALTER TABLE vehicles ENABLE ROW LEVEL SECURITY;CREATE POLICY vehicles_all ON vehicles FOR ALL USING (true);CREATE POLICY bookings_all ON vehicle_bookings FOR ALL USING (true);
